//vip.opstream14.com/20230314/33689_390121a6/index.m3u8"},{"name":"29","slug":"29","filename":"Chuỗi Vòng Quỷ Ám E29","link_embed":"https://vip.opstream14.com/share/95814964b0c42ce64d51e38d917d7fd3","link_m3u8":"https://vip.opstream14.com/20230315/33701_bf073457/index.m3u8"},{"name":"30","slug":"30","filename":"Chuỗi Vòng Quỷ Ám E30","link_embed":"https://vip.opstream14.com/share/b26a828a1b8d319c2c51c7f536ead80d","link_m3u8":"https://vip.opstream14.com/20230315/33702_077559af/index.m3u8"}]}],"time":"35 phút/tập","description":"<p>Chuỗi Vòng Quỷ Ám - The Stone of Affectio xoay quanh tam giác tình yêu giữa Mookda, Pailin và Pruek. Mookda, Pailin cùng yêu Pruek nhưng Pruek chọn đến với Pailin. Điều này khiến Mookda chìm trong đau khổ nên đã tìm đến với ma thuật hắc ám. Về phía Pruek, anh ta vô tình bị điều khiển bởi bùa chú của pháp sư nên đã dùng con dao găm để giết chết Mookda. Sau đó linh hồn của Mookda bị giam giữ trong viên ngọc trai đá, chờ ngày báo thù. 100 năm trôi qua, Phumin (kiếp sau của Pruek) được giao nhiệm vụ điều tra một trường hợp tử vong trong một hang động và tình cờ hóa giải phép thuật đã giam cầm Mookda. Mookda hồi sinh với sự cuồng nộ trong 100 năm và tiếp tục hành trình săn lùng Ployrung (kiếp sau của Pailin), gây ra hàng loạt tội ác. Để ngăn chặn Mookda, Phum và Ployrung phải tìm ra câu chuyện có thật trong quá khứ và tìm cách tiêu diệt con quái vật bên trong Mookda.</p>","tmdb":{"type":"tv","id":"220879","season":1,"vote_average":9,"vote_count":1},"modified":"2025-04-08T13:15:05.000Z","_image_preserved":true},{"id":"63de263b35330788b830b24d","_id":"63de263b35330788b830b24d","title":"Pure Luck","origin_name":"Pure Luck","slug":"pure-luck","year":1991,"type":"single","genre":[{"id":"620a221de0fc277084dfd1c1","name":"Hài Hước","slug":"hai-huoc"}],"country":[{"id":"620a231fe0fc277084dfd7ce","name":"Âu Mỹ","slug":"au-my"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"Pure Luck - 1991","link_embed":"https://vip.opstream14.com/share/387e02e10694ac10252a1a3430cb44cc","link_m3u8":"https://vip.opstream14.com/20230203/30125_02d8d89d/index.m3u8"}]}],"time":"96 Phút","description":"<p>Con gái của một doanh nhân giàu có đã biến mất ở Mexico và mọi nỗ lực tìm kiếm cô đều không thành công. Một nhà tâm lý học, biết rằng cô gái cực kỳ xui xẻo, đã thuyết phục cha cô cử một trong những nhân viên của ông, một kế toán cực kỳ xui xẻo, đến Mexico để tìm cô. Có lẽ anh ta sẽ gặp may mắn, và sự xui xẻo của anh ta có thể giúp tìm ra cô gái kém may mắn.</p>","tmdb":{"type":"movie","id":"19065","season":null,"vote_average":5.5,"vote_count":138},"modified":"2023-02-04T16:32:43.000Z","_image_preserved":true},{"id":"63de273e35330788b830d605","_id":"63de273e35330788b830d605","title":"Sân Chơi Của Quỷ","origin_name":"Devil's Playground","slug":"san-choi-cua-quy","year":2010,"type":"single","genre":[{"id":"620a21b2e0fc277084dfd0c5","name":"Hành Động","slug":"hanh-dong"},{"id":"620a22ace0fc277084dfd531","name":"Kinh Dị","slug":"kinh-di"}],"country":[{"id":"620a231fe0fc277084dfd7ce","name":"Âu Mỹ","slug":"au-my"}],"lang_key":"Vietsub","episode_current":"Full","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"server_name":"Vietsub #1","is_ai":false,"server_data":[{"name":"Full","slug":"full","filename":"Devil's Playground - 2010","link_embed":"https://vip.opstream14.com/share/923afdc34efd0d626a7d62c49f3fb4e8","link_m3u8":"https://vip.opstream14.com/20230203/30122_829b0764/index.m3u8"}]}],"time":"93 Phút","description":"<p>Khi thế giới không chống chọi được với ngày tận thế thây ma, Cole - một lính đánh thuê cừ khôi - đang truy đuổi một người có thể đưa ra phương pháp chữa trị. Không chỉ đối với bệnh dịch mà còn đối với số phận